  z-index: 10;
  pointer-events: none;
  margin-top: 8px;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
  border: 1px solid #eee;
}

.logo-wall-tile:hover::before {
  content: '';
  position: absolute;
  top: 100%;
  left: 50%;
  transform: translateX(-50%);
  border: 6px solid transparent;
  border-bottom-color: white;
  margin-top: -4px;
  pointer-events: none;
  z-index: 11;
}

/* Ensure tooltip stays within viewport on mobile */
@media (max-width: 600px) {
  .logo-wall-tile:hover::after {
    left: 0;
    transform: none;
    font-size: 12px;
    white-space: normal;
    max-width: calc(100% - 16px);
  }

  .logo-wall-tile:hover::before {
    left: 15px;
    transform: none;
  }
}

